const now = new Date();
const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

// Service health
const healthData = $('获取服务状态').first().json;
const services = healthData.services || healthData.components || {};
const svc = (name) => (services[name]?.status === 'healthy' || services[name]?.status === 'ok' || healthData.status === 'healthy') ? '\u2705' : '\u274c';

// Article count
const totalArticles = $('获取文章总数').first().json.pagination?.total || 0;

// Todos
const todoCount = ($('获取待办事项').first().json.memos || []).length;

// RSS fetch stats from ActivityLog
const rssLogs = $('获取RSS采集详情').first().json.data?.items || [];
const rssSuccess = rssLogs.filter(l => l.status === 'success').length;
const rssFailed = rssLogs.filter(l => l.status === 'failed').length;

// Build failed articles list
const failedArticles = rssLogs
  .filter(l => l.status === 'failed' && l.detail)
  .map(l => {
    try {
      const d = typeof l.detail === 'string' ? JSON.parse(l.detail) : l.detail;
      const articles = d.articles || d.failed || [];
      return articles.map(a => `- [${a.title || 'Untitled'}](${a.url || ''}) - ${a.error || l.summary || ''}`);
    } catch(e) { return []; }
  })
  .flat();

// Dataset stats
const datasets = $('获取文章总数').first().json.data?.items || [];
const datasetLines = datasets.map(d => `  - ${d.name}: ${d.document_count || 0} \u7bc7`);

// Build markdown
let md = `### \ud83d\udcca \u6bcf\u65e5\u77e5\u8bc6\u5e93\u6458\u8981 - ${dateStr}\n\n`;

md += `#### \ud83d\udce6 \u670d\u52a1\u72b6\u6001\n\n`;
md += `| \u670d\u52a1 | \u72b6\u6001 |\n|------|------|\n`;
md += `| Bellkeeper | ${svc('bellkeeper')} |\n`;
md += `| RagFlow | ${svc('ragflow')} |\n`;
md += `| Firecrawl | ${svc('firecrawl')} |\n\n`;

md += `#### \ud83d\udce5 \u4eca\u65e5\u5185\u5bb9\u91c7\u96c6\n\n`;
if (rssSuccess > 0 || rssFailed > 0) {
  md += `##### RSS \u5b9a\u65f6\u91c7\u96c6\n\n`;
  md += `| \u6307\u6807 | \u6570\u91cf |\n|------|------|\n`;
  md += `| \u6210\u529f\u5165\u5e93 | ${rssSuccess} \u7bc7 |\n`;
  md += `| \u5931\u8d25 | ${rssFailed} \u7bc7 |\n\n`;
  if (failedArticles.length > 0) {
    md += `**\u5931\u8d25\u6587\u7ae0:**\n\n`;
    md += failedArticles.join('\n') + '\n\n';
  }
} else {
  md += `*\u4eca\u65e5\u65e0 RSS \u91c7\u96c6\u8bb0\u5f55*\n\n`;
}

md += `#### \ud83d\udcda \u77e5\u8bc6\u5e93\u7edf\u8ba1\n\n`;
md += `- **\u6587\u7ae0\u603b\u6570**: ${totalArticles} \u7bc7\n\n`;
if (datasetLines.length > 0) {
  md += `| \u6570\u636e\u96c6 | \u6587\u7ae0\u6570 |\n|---------|---------|\n`;
  md += datasetLines.map(l => l.replace(/^  - /, '| ').replace(': ', '| ')).join(' \u7bc7\n') + ' \u7bc7\n\n';
}

md += `#### \ud83d\udcdd \u5f85\u529e\u4e8b\u9879\n\n`;
md += `- \u672a\u5b8c\u6210: ${todoCount} \u9879`;

return [{ json: { room: 'daily', markdown: md, date: dateStr } }];
